[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div></div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
    @page {
        size: A4;
        margin: 10mm 10mm 12mm 10mm;
    }

    .print-format {
        font-family: Arial, Helvetica, sans-serif;
        font-size: 10px;
        color: #222222;
        line-height: 1.25;
    }

    .coa-wrapper {
        width: 100%;
        margin: 0;
        padding: 0;
    }

    .coa-title {
        text-align: center;
        font-size: 18px;
        font-weight: bold;
        letter-spacing: 3px;
        margin: 0;
        padding: 0;
    }

    .coa-subtitle {
        text-align: center;
        font-size: 8px;
        color: #555555;
        margin-top: 3px;
        margin-bottom: 10px;
    }

    table {
        width: 100%;
        border-collapse: collapse;
        border-spacing: 0;
    }

    .information-table {
        margin-bottom: 10px;
        table-layout: fixed;
    }

    .information-table td {
        border: 1px solid #999999;
        padding: 4px 6px;
        vertical-align: middle;
        word-wrap: break-word;
    }

    .information-table .label-cell {
        width: 18%;
        font-weight: bold;
        background-color: #eeeeee;
        white-space: nowrap;
    }

    .information-table .value-cell {
        width: 32%;
    }

    .readings-table {
        table-layout: fixed;
        margin-bottom: 10px;
    }

    .readings-table th,
    .readings-table td {
        border: 1px solid #999999;
        padding: 5px 6px;
        vertical-align: middle;
        word-wrap: break-word;
    }

    .readings-table th {
        background-color: #e6e6e6;
        font-weight: bold;
        text-align: left;
    }

    .readings-table .serial-column {
        width: 5%;
        text-align: center;
    }

    .readings-table .parameter-column {
        width: 32%;
    }

    .readings-table .criteria-column {
        width: 27%;
    }

    .readings-table .result-column {
        width: 22%;
    }

    .readings-table .status-column {
        width: 14%;
    }

    .center {
        text-align: center;
    }

    .status-accepted {
        color: #168425;
        font-weight: bold;
    }

    .status-rejected {
        color: #c00000;
        font-weight: bold;
    }

    .status-other {
        color: #333333;
        font-weight: bold;
    }

    .overall-result {
        border: 2px solid #168425;
        color: #168425;
        font-size: 11px;
        font-weight: bold;
        text-align: center;
        padding: 7px 8px;
        margin-top: 4px;
        margin-bottom: 8px;
    }

    .overall-result-fail {
        border-color: #c00000;
        color: #c00000;
    }

    .overall-result-pending {
        border-color: #b07800;
        color: #8a5d00;
    }

    .remarks-section {
        margin-top: 7px;
        min-height: 28px;
        line-height: 1.4;
    }

    .remarks-label {
        font-weight: bold;
    }

    .signature-table {
        margin-top: 48px;
        table-layout: fixed;
    }

    .signature-table td {
        width: 33.33%;
        text-align: center;
        vertical-align: bottom;
        padding: 0 8px;
        border: 0;
    }

    .signature-name {
        min-height: 16px;
        font-size: 9px;
        font-weight: normal;
    }

    .signature-role {
        font-size: 9px;
        margin-top: 2px;
    }

    .signature-line {
        border-top: 1px solid #777777;
        margin-top: 5px;
        padding-top: 3px;
    }

    .footer-note {
        border-top: 1px solid #dddddd;
        margin-top: 16px;
        padding-top: 5px;
        font-size: 8px;
        color: #777777;
    }

    .empty-value {
        color: #777777;
    }

    .no-data {
        text-align: center;
        color: #777777;
        font-style: italic;
        padding: 12px !important;
    }
</style>

{# --------------------------------------------------------- #}
{# Fetch batch dates dynamically                            #}
{# --------------------------------------------------------- #}

{% set batch_manufacturing_date = "" %}
{% set batch_expiry_date = "" %}

{% if doc.batch_no %}
    {% set batch_manufacturing_date =
        frappe.db.get_value("Batch", doc.batch_no, "manufacturing_date")
        or ""
    %}

    {% set batch_expiry_date =
        frappe.db.get_value("Batch", doc.batch_no, "expiry_date")
        or ""
    %}
{% endif %}

{# --------------------------------------------------------- #}
{# Determine displayed inspection status                    #}
{# Draft Quality Inspection is shown as In Process           #}
{# --------------------------------------------------------- #}

{% if doc.docstatus == 0 %}
    {% set displayed_inspection_status = "In Process" %}
{% elif doc.docstatus == 2 %}
    {% set displayed_inspection_status = "Cancelled" %}
{% else %}
    {% set displayed_inspection_status = doc.status or "" %}
{% endif %}

{# --------------------------------------------------------- #}
{# Optional custom signature fields                         #}
{# These remain blank when custom fields do not exist        #}
{# --------------------------------------------------------- #}

{% set analyzed_by = doc.inspected_by or "" %}
{% set checked_by = doc.get("checked_by") or doc.verified_by or "" %}
{% set approved_by = doc.get("approved_by") or "" %}

<div class="coa-wrapper">

    <div class="coa-title">
        CERTIFICATE OF ANALYSIS
    </div>

    <div class="coa-subtitle">
        QI-{{ doc.name or "" }}
        &nbsp;|&nbsp;
        Date:
        {% if doc.report_date %}
            {{ frappe.utils.formatdate(doc.report_date, "dd-mm-yyyy") }}
        {% else %}
            -
        {% endif %}
    </div>

    <!-- Main information table -->
    <table class="information-table">
        <tbody>
            <tr>
                <td class="label-cell">Product</td>
                <td class="value-cell">
                    {{ doc.item_name or doc.description or "-" }}
                </td>

                <td class="label-cell">Item Code</td>
                <td class="value-cell">
                    {{ doc.item_code or "-" }}
                </td>
            </tr>

            <tr>
                <td class="label-cell">Batch No.</td>
                <td class="value-cell">
                    {{ doc.batch_no or "-" }}
                </td>

                <td class="label-cell">Sample Size</td>
                <td class="value-cell">
                    {% if doc.sample_size is not none %}
                        {{ doc.sample_size }}
                    {% else %}
                        -
                    {% endif %}
                </td>
            </tr>

            <tr>
                <td class="label-cell">Mfg. Date</td>
                <td class="value-cell">
                    {% if batch_manufacturing_date %}
                        {{ frappe.utils.formatdate(
                            batch_manufacturing_date,
                            "dd-mm-yyyy"
                        ) }}
                    {% else %}
                        -
                    {% endif %}
                </td>

                <td class="label-cell">Expiry Date</td>
                <td class="value-cell">
                    {% if batch_expiry_date %}
                        {{ frappe.utils.formatdate(
                            batch_expiry_date,
                            "dd-mm-yyyy"
                        ) }}
                    {% else %}
                        -
                    {% endif %}
                </td>
            </tr>

            <tr>
                <td class="label-cell">Inspection Type</td>
                <td class="value-cell">
                    {{ doc.inspection_type or "-" }}
                </td>

                <td class="label-cell">Reference</td>
                <td class="value-cell">
                    {% if doc.reference_name %}
                        {{ doc.reference_name }}
                    {% elif doc.reference_type %}
                        {{ doc.reference_type }}
                    {% else %}
                        -
                    {% endif %}
                </td>
            </tr>

            <tr>
                <td class="label-cell">Inspection Status</td>
                <td class="value-cell">
                    {{ displayed_inspection_status or "-" }}
                </td>

                <td class="label-cell">QI Number</td>
                <td class="value-cell">
                    {{ doc.name or "-" }}
                </td>
            </tr>
        </tbody>
    </table>

    <!-- Dynamic inspection readings -->
    <table class="readings-table">
        <thead>
            <tr>
                <th class="serial-column">#</th>
                <th class="parameter-column">Test Parameter</th>
                <th class="criteria-column">Specification</th>
                <th class="result-column">Result</th>
                <th class="status-column">Status</th>
            </tr>
        </thead>

        <tbody>
            {% if doc.readings %}

                {% for row in doc.readings %}

                    {# ----------------------------------------- #}
                    {# Build specification/acceptance criteria   #}
                    {# ----------------------------------------- #}

                    {% set criteria = namespace(value="") %}

                    {% if row.formula_based_criteria
                        and row.acceptance_formula %}

                        {% set criteria.value =
                            row.acceptance_formula
                        %}

                    {% elif row.numeric %}

                        {% if row.min_value is not none
                            and row.max_value is not none %}

                            {% set criteria.value =
                                row.min_value|string
                                ~ " - "
                                ~ row.max_value|string
                            %}

                        {% elif row.min_value is not none %}

                            {% set criteria.value =
                                "Minimum " ~ row.min_value|string
                            %}

                        {% elif row.max_value is not none %}

                            {% set criteria.value =
                                "Maximum " ~ row.max_value|string
                            %}

                        {% endif %}

                    {% elif row.value %}

                        {% set criteria.value = row.value %}

                    {% endif %}

                    {# ----------------------------------------- #}
                    {# Collect all populated reading values      #}
                    {# ----------------------------------------- #}

                    {% set result = namespace(value="", count=0) %}

                    {% if row.numeric %}

                        {% for reading_number in range(1, 11) %}

                            {% set reading_field =
                                "reading_" ~ reading_number
                            %}

                            {% set reading =
                                row.get(reading_field)
                            %}

                            {% if reading is not none
                                and reading|string|trim != "" %}

                                {% if result.count > 0 %}
                                    {% set result.value =
                                        result.value
                                        ~ ", "
                                        ~ reading|string
                                    %}
                                {% else %}
                                    {% set result.value =
                                        reading|string
                                    %}
                                {% endif %}

                                {% set result.count =
                                    result.count + 1
                                %}

                            {% endif %}

                        {% endfor %}

                    {% else %}

                        {% if row.reading_value is not none
                            and row.reading_value|string|trim != "" %}

                            {% set result.value =
                                row.reading_value|string
                            %}

                        {% endif %}

                    {% endif %}

                    <tr>
                        <td class="serial-column">
                            {{ loop.index }}
                        </td>

                        <td class="parameter-column">
                            {{ row.specification or "-" }}
                        </td>

                        <td class="criteria-column">
                            {% if criteria.value %}
                                {{ criteria.value }}
                            {% else %}
                                <span class="empty-value">-</span>
                            {% endif %}
                        </td>

                        <td class="result-column">
                            {% if result.value %}
                                {{ result.value }}
                            {% else %}
                                <span class="empty-value">-</span>
                            {% endif %}
                        </td>

                        <td class="status-column">
                            {% set row_status =
                                row.status or ""
                            %}

                            {% if row_status == "Accepted" %}

                                <span class="status-accepted">
                                    {{ row_status }}
                                </span>

                            {% elif row_status == "Rejected" %}

                                <span class="status-rejected">
                                    {{ row_status }}
                                </span>

                            {% else %}

                                <span class="status-other">
                                    {{ row_status or "-" }}
                                </span>

                            {% endif %}
                        </td>
                    </tr>

                {% endfor %}

            {% else %}

                <tr>
                    <td colspan="5" class="no-data">
                        No inspection readings are available.
                    </td>
                </tr>

            {% endif %}
        </tbody>
    </table>

    <!-- Dynamic overall result -->
    {% if doc.docstatus == 0 %}

        <div class="overall-result overall-result-pending">
            Overall Result: IN PROCESS —
            Quality inspection has not been submitted.
        </div>

    {% elif doc.status == "Accepted" %}

        <div class="overall-result">
            Overall Result: PASS —
            The batch complies with the specifications.
        </div>

    {% elif doc.status == "Rejected" %}

        <div class="overall-result overall-result-fail">
            Overall Result: FAIL —
            The batch does not comply with the specifications.
        </div>

    {% elif doc.status == "Cancelled" or doc.docstatus == 2 %}

        <div class="overall-result overall-result-fail">
            Overall Result: CANCELLED
        </div>

    {% else %}

        <div class="overall-result overall-result-pending">
            Overall Result:
            {{ doc.status or "Pending" }}
        </div>

    {% endif %}

    <!-- Remarks -->
    <div class="remarks-section">
        <span class="remarks-label">Remarks:</span>

        {% if doc.remarks %}
            {{ doc.remarks }}
        {% else %}
            -
        {% endif %}
    </div>

    <!-- Signature section -->
    <table class="signature-table">
        <tbody>
            <tr>
                <td>
                    <div class="signature-name">
                        {{ analyzed_by or "&nbsp;" }}
                    </div>

                    <div class="signature-line">
                        Analyzed By (QC)
                    </div>
                </td>

                <td>
                    <div class="signature-name">
                        {{ checked_by or "&nbsp;" }}
                    </div>

                    <div class="signature-line">
                        Checked By (QC Head)
                    </div>
                </td>

                <td>
                    <div class="signature-name">
                        {{ approved_by or "&nbsp;" }}
                    </div>

                    <div class="signature-line">
                        Approved By (QA)
                    </div>
                </td>
            </tr>
        </tbody>
    </table>

    <!-- Footer -->
    <div class="footer-note">
        This certificate is issued for the batch stated above and pertains
        only to the sample(s) tested.

        Generated from {{ doc.name or "Quality Inspection" }}

        {% if doc.report_date %}
            on
            {{ frappe.utils.formatdate(
                doc.report_date,
                "dd-mm-yyyy"
            ) }}.
        {% endif %}
    </div>

</div>"}]
